// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title AgentRegistry
 * @notice Stores all agent listings on-chain
 */
contract AgentRegistry is Ownable, ReentrancyGuard {
    struct Agent {
        uint256 id;
        string name;
        string category;
        string framework;
        uint256 pricePerCall;
        address payable wallet;
        uint256 stakedAmount;
        uint256 totalTasks;
        uint256 successCount;
        bool isActive;
        bool isFeatured;
        uint256 listingFee;
        string endpointUrl;
        string description;
        uint256 registeredAt;
    }

    mapping(uint256 => Agent) public agents;
    uint256 public agentCount;
    uint256 public constant MIN_STAKE = 100 * 10 ** 18;
    uint256 public constant LISTING_FEE = 5 * 10 ** 18;
    address public treasury;
    IERC20 public hlusd;
    address public vault;

    // Mapping from wallet to agent IDs
    mapping(address => uint256[]) public ownerAgents;

    event AgentRegistered(uint256 indexed agentId, address indexed wallet, string name);
    event AgentStatusUpdated(uint256 indexed agentId, bool isActive);
    event AgentDelisted(uint256 indexed agentId);
    event AgentStatsUpdated(uint256 indexed agentId, uint256 totalTasks, uint256 successCount);

    constructor(address _hlusd, address _treasury) Ownable(msg.sender) {
        hlusd = IERC20(_hlusd);
        treasury = _treasury;
    }

    function setVault(address _vault) external onlyOwner {
        vault = _vault;
    }

    function registerAgent(
        string memory _name,
        string memory _category,
        string memory _framework,
        uint256 _pricePerCall,
        string memory _endpointUrl,
        string memory _description,
        uint256 _stakeAmount
    ) external nonReentrant returns (uint256) {
        require(_stakeAmount >= MIN_STAKE, "Stake below minimum");
        require(
            hlusd.allowance(msg.sender, address(this)) >= _stakeAmount + LISTING_FEE,
            "Insufficient allowance"
        );

        // Transfer listing fee to treasury
        require(hlusd.transferFrom(msg.sender, treasury, LISTING_FEE), "Listing fee transfer failed");

        // Transfer stake to vault
        require(hlusd.transferFrom(msg.sender, vault, _stakeAmount), "Stake transfer failed");

        agentCount++;
        agents[agentCount] = Agent({
            id: agentCount,
            name: _name,
            category: _category,
            framework: _framework,
            pricePerCall: _pricePerCall,
            wallet: payable(msg.sender),
            stakedAmount: _stakeAmount,
            totalTasks: 0,
            successCount: 0,
            isActive: true,
            isFeatured: false,
            listingFee: LISTING_FEE,
            endpointUrl: _endpointUrl,
            description: _description,
            registeredAt: block.timestamp
        });

        ownerAgents[msg.sender].push(agentCount);

        emit AgentRegistered(agentCount, msg.sender, _name);
        return agentCount;
    }

    function getAgent(uint256 _agentId) external view returns (Agent memory) {
        require(_agentId > 0 && _agentId <= agentCount, "Agent not found");
        return agents[_agentId];
    }

    function getAllAgents() external view returns (Agent[] memory) {
        Agent[] memory allAgents = new Agent[](agentCount);
        for (uint256 i = 1; i <= agentCount; i++) {
            allAgents[i - 1] = agents[i];
        }
        return allAgents;
    }

    function getAgentsByCategory(string memory _category) external view returns (Agent[] memory) {
        uint256 count = 0;
        for (uint256 i = 1; i <= agentCount; i++) {
            if (keccak256(bytes(agents[i].category)) == keccak256(bytes(_category))) {
                count++;
            }
        }
        Agent[] memory result = new Agent[](count);
        uint256 idx = 0;
        for (uint256 i = 1; i <= agentCount; i++) {
            if (keccak256(bytes(agents[i].category)) == keccak256(bytes(_category))) {
                result[idx] = agents[i];
                idx++;
            }
        }
        return result;
    }

    function getTopAgents(uint256 _limit) external view returns (Agent[] memory) {
        uint256 len = _limit > agentCount ? agentCount : _limit;
        Agent[] memory sorted = new Agent[](agentCount);
        for (uint256 i = 1; i <= agentCount; i++) {
            sorted[i - 1] = agents[i];
        }
        // Simple bubble sort by success rate
        for (uint256 i = 0; i < sorted.length; i++) {
            for (uint256 j = i + 1; j < sorted.length; j++) {
                uint256 rateI = sorted[i].totalTasks > 0
                    ? (sorted[i].successCount * 10000) / sorted[i].totalTasks
                    : 0;
                uint256 rateJ = sorted[j].totalTasks > 0
                    ? (sorted[j].successCount * 10000) / sorted[j].totalTasks
                    : 0;
                if (rateJ > rateI) {
                    Agent memory tmp = sorted[i];
                    sorted[i] = sorted[j];
                    sorted[j] = tmp;
                }
            }
        }
        Agent[] memory top = new Agent[](len);
        for (uint256 i = 0; i < len; i++) {
            top[i] = sorted[i];
        }
        return top;
    }

    function updateAgentStatus(uint256 _agentId, bool _isActive) external {
        Agent storage agent = agents[_agentId];
        require(agent.id > 0, "Agent not found");
        require(
            msg.sender == agent.wallet || msg.sender == owner(),
            "Not authorized"
        );
        agent.isActive = _isActive;
        emit AgentStatusUpdated(_agentId, _isActive);
    }

    function delistAgent(uint256 _agentId) external {
        Agent storage agent = agents[_agentId];
        require(agent.id > 0, "Agent not found");
        require(msg.sender == agent.wallet, "Not agent owner");
        agent.isActive = false;
        emit AgentDelisted(_agentId);
    }

    // --- Functions called by other contracts ---

    function incrementTaskCount(uint256 _agentId) external {
        agents[_agentId].totalTasks++;
    }

    function incrementSuccessCount(uint256 _agentId) external {
        agents[_agentId].successCount++;
    }

    function suspendAgent(uint256 _agentId) external {
        agents[_agentId].isActive = false;
        emit AgentStatusUpdated(_agentId, false);
    }

    function getAgentWallet(uint256 _agentId) external view returns (address payable) {
        return agents[_agentId].wallet;
    }

    function getAgentStake(uint256 _agentId) external view returns (uint256) {
        return agents[_agentId].stakedAmount;
    }

    function reduceStake(uint256 _agentId, uint256 _amount) external {
        agents[_agentId].stakedAmount -= _amount;
    }

    function addStake(uint256 _agentId, uint256 _amount) external {
        agents[_agentId].stakedAmount += _amount;
    }

    // --- Testnet only: set mock stats ---

    function setMockStats(uint256 _agentId, uint256 _totalTasks, uint256 _successCount) external onlyOwner {
        agents[_agentId].totalTasks = _totalTasks;
        agents[_agentId].successCount = _successCount;
        emit AgentStatsUpdated(_agentId, _totalTasks, _successCount);
    }

    function setFeatured(uint256 _agentId, bool _featured) external onlyOwner {
        agents[_agentId].isFeatured = _featured;
    }
}

contracts/AgentVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

/**
 * @title AgentVault
 * @notice Holds all payments and stake in escrow with payment splitting
 */
contract AgentVault is Ownable, ReentrancyGuard {
    IERC20 public hlusd;
    address public treasury;

    // Payment split constants (percentages)
    uint256 public constant AGENT_SHARE = 85;
    uint256 public constant PROTOCOL_FEE = 10;
    uint256 public constant REPUTATION_POOL_FEE = 5;
    uint256 public constant ARENA_PREMIUM = 2;

    // Slash distribution
    uint256 public constant SLASH_TO_USER = 70;
    uint256 public constant SLASH_TO_TREASURY = 20;
    uint256 public constant SLASH_BURN = 10;
    address public constant BURN_ADDRESS = 0x000000000000000000000000000000000000dEaD;

    mapping(uint256 => uint256) public agentStakes;
    mapping(uint256 => uint256) public agentEarnings;
    mapping(uint256 => uint256) public taskEscrow;
    mapping(uint256 => address) public taskPayer;
    mapping(uint256 => uint256) public taskAgentId;
    uint256 public treasuryBalance;
    uint256 public reputationPool;

    // Authorized contracts
    mapping(address => bool) public authorized;

    event TaskPaid(uint256 indexed taskId, uint256 indexed agentId, uint256 amount, address user);
    event PaymentReleased(uint256 indexed taskId, uint256 indexed agentId, uint256 amount);
    event UserRefunded(uint256 indexed taskId, address indexed user, uint256 amount);
    event AgentSlashed(uint256 indexed agentId, uint256 amount, address indexed user);
    event StakeDeposited(uint256 indexed agentId, uint256 amount);
    event StakeWithdrawn(uint256 indexed agentId, uint256 amount);
    event EarningsWithdrawn(uint256 indexed agentId, uint256 amount);
    event TreasuryWithdrawn(address indexed to, uint256 amount);

    modifier onlyAuthorized() {
        require(authorized[msg.sender] || msg.sender == owner(), "Not authorized");
        _;
    }

    constructor(address _hlusd, address _treasury) Ownable(msg.sender) {
        hlusd = IERC20(_hlusd);
        treasury = _treasury;
    }

    function setAuthorized(address _contract, bool _status) external onlyOwner {
        authorized[_contract] = _status;
    }

    function payForTask(
        uint256 _agentId,
        uint256 _taskId,
        uint256 _amount,
        address _user,
        bool _isArena
    ) external onlyAuthorized nonReentrant {
        require(_amount > 0, "Amount must be > 0");
        require(taskEscrow[_taskId] == 0, "Task already paid");

        require(hlusd.transferFrom(_user, address(this), _amount), "Payment transfer failed");

        taskEscrow[_taskId] = _amount;
        taskPayer[_taskId] = _user;
        taskAgentId[_taskId] = _agentId;

        emit TaskPaid(_taskId, _agentId, _amount, _user);
    }

    function releasePayment(uint256 _taskId, uint256 _agentId) external onlyAuthorized nonReentrant {
        uint256 amount = taskEscrow[_taskId];
        require(amount > 0, "No escrowed amount");

        uint256 agentAmount = (amount * AGENT_SHARE) / 100;
        uint256 protocolAmount = (amount * PROTOCOL_FEE) / 100;
        uint256 reputationAmount = (amount * REPUTATION_POOL_FEE) / 100;

        agentEarnings[_agentId] += agentAmount;
        treasuryBalance += protocolAmount;
        reputationPool += reputationAmount;

        taskEscrow[_taskId] = 0;

        emit PaymentReleased(_taskId, _agentId, amount);
    }

    function refundUser(uint256 _taskId, address _user) external onlyAuthorized nonReentrant {
        uint256 amount = taskEscrow[_taskId];
        require(amount > 0, "No escrowed amount");

        taskEscrow[_taskId] = 0;
        require(hlusd.transfer(_user, amount), "Refund failed");

        emit UserRefunded(_taskId, _user, amount);
    }

    function slashAgent(uint256 _agentId, uint256 _taskId, address _user) external onlyAuthorized nonReentrant {
        uint256 stake = agentStakes[_agentId];
        require(stake > 0, "No stake to slash");

        uint256 slashAmount = (stake * 20) / 100; // 20% of stake
        uint256 userCompensation = (slashAmount * SLASH_TO_USER) / 100;
        uint256 treasuryShareAmount = (slashAmount * SLASH_TO_TREASURY) / 100;
        uint256 burnAmount = (slashAmount * SLASH_BURN) / 100;

        agentStakes[_agentId] -= slashAmount;

        require(hlusd.transfer(_user, userCompensation), "User compensation failed");
        treasuryBalance += treasuryShareAmount;
        require(hlusd.transfer(BURN_ADDRESS, burnAmount), "Burn failed");

        emit AgentSlashed(_agentId, slashAmount, _user);
    }

    function depositStake(uint256 _agentId, uint256 _amount) external nonReentrant {
        require(_amount > 0, "Amount must be > 0");
        require(hlusd.transferFrom(msg.sender, address(this), _amount), "Transfer failed");
        agentStakes[_agentId] += _amount;
        emit StakeDeposited(_agentId, _amount);
    }

    function withdrawStake(uint256 _agentId, uint256 _amount) external nonReentrant {
        require(agentStakes[_agentId] >= _amount, "Insufficient stake");
        agentStakes[_agentId] -= _amount;
        require(hlusd.transfer(msg.sender, _amount), "Transfer failed");
        emit StakeWithdrawn(_agentId, _amount);
    }

    function withdrawAgentEarnings(uint256 _agentId) external nonReentrant {
        uint256 amount = agentEarnings[_agentId];
        require(amount > 0, "No earnings");
        agentEarnings[_agentId] = 0;
        require(hlusd.transfer(msg.sender, amount), "Transfer failed");
        emit EarningsWithdrawn(_agentId, amount);
    }

    function withdrawTreasury(address _to, uint256 _amount) external onlyOwner nonReentrant {
        require(_amount <= treasuryBalance, "Insufficient treasury");
        treasuryBalance -= _amount;
        require(hlusd.transfer(_to, _amount), "Transfer failed");
        emit TreasuryWithdrawn(_to, _amount);
    }

    // Initialize stake when agent registers (called by registry)
    function initStake(uint256 _agentId, uint256 _amount) external onlyAuthorized {
        agentStakes[_agentId] += _amount;
    }
}

contracts/ArenaEngine.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

interface IAgentRegistryForArena {
    function agents(uint256 agentId) external view returns (
        uint256 id, string memory name, string memory category,
        string memory framework, uint256 pricePerCall,
        address payable wallet, uint256 stakedAmount,
        uint256 totalTasks, uint256 successCount,
        bool isActive, bool isFeatured, uint256 listingFee,
        string memory endpointUrl, string memory description,
        uint256 registeredAt
    );
}

interface IAgentVaultForArena {
    function payForTask(uint256 agentId, uint256 taskId, uint256 amount, address user, bool isArena) external;
}

interface ITaskLedgerForArena {
    function createTask(
        uint256 agentId, address user, string memory taskType,
        uint256 paidAmount, bool isArena, bytes32 inputHash
    ) external returns (uint256);
}

/**
 * @title ArenaEngine
 * @notice Manages reverse auction arena battles
 */
contract ArenaEngine is Ownable, ReentrancyGuard {
    enum ArenaStatus { OPEN, SELECTING, CLOSED, CANCELLED }

    struct Arena {
        uint256 id;
        address user;
        string taskDescription;
        string category;
        uint256 maxBudget;
        uint256 deadline;
        ArenaStatus status;
        uint256 winnerAgentId;
        uint256 winningBid;
        uint256 createdAt;
    }

    struct Bid {
        uint256 agentId;
        uint256 amount;
        uint256 submittedAt;
        bool selected;
    }

    mapping(uint256 => Arena) public arenas;
    mapping(uint256 => Bid[]) public arenaBids;
    mapping(uint256 => mapping(uint256 => bool)) public agentHasBid; // arenaId => agentId => hasBid
    uint256 public arenaCount;
    uint256 public constant ARENA_FEE_PREMIUM = 2;

    IERC20 public hlusd;
    IAgentRegistryForArena public registry;
    address public vault;
    address public taskLedger;

    event ArenaCreated(uint256 indexed arenaId, address indexed user, string category, uint256 maxBudget);
    event BidSubmitted(uint256 indexed arenaId, uint256 indexed agentId, uint256 bidAmount);
    event WinnerSelected(uint256 indexed arenaId, uint256 indexed agentId, uint256 bidAmount);
    event ArenaCancelled(uint256 indexed arenaId);

    constructor(
        address _hlusd,
        address _registry,
        address _vault,
        address _taskLedger
    ) Ownable(msg.sender) {
        hlusd = IERC20(_hlusd);
        registry = IAgentRegistryForArena(_registry);
        vault = _vault;
        taskLedger = _taskLedger;
    }

    function createArena(
        string memory _taskDescription,
        string memory _category,
        uint256 _maxBudget,
        uint256 _durationSeconds
    ) external nonReentrant returns (uint256) {
        require(_maxBudget > 0, "Budget must be > 0");
        require(_durationSeconds >= 30, "Min duration 30s");

        // User deposits maxBudget into escrow
        require(
            hlusd.transferFrom(msg.sender, address(this), _maxBudget),
            "Budget transfer failed"
        );

        arenaCount++;
        arenas[arenaCount] = Arena({
            id: arenaCount,
            user: msg.sender,
            taskDescription: _taskDescription,
            category: _category,
            maxBudget: _maxBudget,
            deadline: block.timestamp + _durationSeconds,
            status: ArenaStatus.OPEN,
            winnerAgentId: 0,
            winningBid: 0,
            createdAt: block.timestamp
        });

        emit ArenaCreated(arenaCount, msg.sender, _category, _maxBudget);
        return arenaCount;
    }

    function submitBid(uint256 _arenaId, uint256 _agentId, uint256 _bidAmount) external {
        Arena storage arena = arenas[_arenaId];
        require(arena.id > 0, "Arena not found");
        require(arena.status == ArenaStatus.OPEN, "Arena not open");
        require(block.timestamp <= arena.deadline, "Arena deadline passed");
        require(_bidAmount <= arena.maxBudget, "Bid exceeds budget");
        require(!agentHasBid[_arenaId][_agentId], "Agent already bid");

        // Check agent is active and has sufficient reputation
        (
            uint256 id, , , , , , , , uint256 successCount,
            bool isActive, , , , ,
        ) = registry.agents(_agentId);
        require(id > 0, "Agent not found");
        require(isActive, "Agent not active");

        agentHasBid[_arenaId][_agentId] = true;

        arenaBids[_arenaId].push(Bid({
            agentId: _agentId,
            amount: _bidAmount,
            submittedAt: block.timestamp,
            selected: false
        }));

        emit BidSubmitted(_arenaId, _agentId, _bidAmount);
    }

    function selectWinner(uint256 _arenaId, uint256 _agentId) external nonReentrant {
        Arena storage arena = arenas[_arenaId];
        require(arena.id > 0, "Arena not found");
        require(msg.sender == arena.user, "Not arena creator");
        require(
            arena.status == ArenaStatus.OPEN || arena.status == ArenaStatus.SELECTING,
            "Arena not selectable"
        );

        // Find the bid
        Bid[] storage bids = arenaBids[_arenaId];
        bool found = false;
        uint256 bidAmount = 0;
        for (uint256 i = 0; i < bids.length; i++) {
            if (bids[i].agentId == _agentId) {
                bids[i].selected = true;
                bidAmount = bids[i].amount;
                found = true;
                break;
            }
        }
        require(found, "Agent has no bid");

        arena.status = ArenaStatus.CLOSED;
        arena.winnerAgentId = _agentId;
        arena.winningBid = bidAmount;

        // Refund difference to user
        uint256 refund = arena.maxBudget - bidAmount;
        if (refund > 0) {
            require(hlusd.transfer(arena.user, refund), "Refund failed");
        }

        // Transfer winning bid to vault for payment processing
        require(hlusd.transfer(vault, bidAmount), "Transfer to vault failed");

        emit WinnerSelected(_arenaId, _agentId, bidAmount);
    }

    function cancelArena(uint256 _arenaId) external nonReentrant {
        Arena storage arena = arenas[_arenaId];
        require(arena.id > 0, "Arena not found");
        require(
            msg.sender == arena.user || block.timestamp > arena.deadline,
            "Not authorized"
        );
        require(arena.status == ArenaStatus.OPEN, "Arena not open");

        arena.status = ArenaStatus.CANCELLED;
        require(hlusd.transfer(arena.user, arena.maxBudget), "Refund failed");

        emit ArenaCancelled(_arenaId);
    }

    function getArena(uint256 _arenaId) external view returns (Arena memory) {
        require(arenas[_arenaId].id > 0, "Arena not found");
        return arenas[_arenaId];
    }

    function getArenaBids(uint256 _arenaId) external view returns (Bid[] memory) {
        return arenaBids[_arenaId];
    }

    function getOpenArenas() external view returns (Arena[] memory) {
        uint256 count = 0;
        for (uint256 i = 1; i <= arenaCount; i++) {
            if (arenas[i].status == ArenaStatus.OPEN) count++;
        }
        Arena[] memory result = new Arena[](count);
        uint256 idx = 0;
        for (uint256 i = 1; i <= arenaCount; i++) {
            if (arenas[i].status == ArenaStatus.OPEN) {
                result[idx] = arenas[i];
                idx++;
            }
        }
        return result;
    }

    function getArenaBidCount(uint256 _arenaId) external view returns (uint256) {
        return arenaBids[_arenaId].length;
    }
}

